const defaultAvatarState: AvatarState = {};

let avatarLibrary: AvatarLibrary = { ...defaultAvatarLibrary };
let avatarState: AvatarState = { ...defaultAvatarState };
let isInitialized = false;
let db: IDBDatabase | null = null;

function openDatabase(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    if (db) {
      resolve(db);
      return;
    }

    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => {
      console.error('打开 IndexedDB 失败:', request.error);
      reject(request.error);
    };

    request.onsuccess = () => {
      db = request.result;
      console.log('IndexedDB 连接成功');
      resolve(db);
    };

    request.onupgradeneeded = event => {
      const database = (event.target as IDBOpenDBRequest).result;
      if (!database.objectStoreNames.contains(STORE_NAME)) {
        database.createObjectStore(STORE_NAME);
        console.log('创建 IndexedDB 存储对象:', STORE_NAME);
      }
    };
  });
}

async function loadFromIndexedDB<T>(key: string): Promise<T | null> {
  try {
    const database = await openDatabase();
    return new Promise((resolve, reject) => {
      const transaction = database.transaction([STORE_NAME], 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.get(key);

      request.onsuccess = () => {
        resolve(request.result || null);
      };

      request.onerror = () => {
        console.error(`从 IndexedDB 读取 ${key} 失败:`, request.error);
        reject(request.error);
      };
    });
  } catch (error) {
    console.error(`加载 IndexedDB ${key} 数据失败:`, error);
    return null;
  }
}

async function saveToIndexedDB<T>(key: string, data: T): Promise<void> {
  const database = await openDatabase();
  return new Promise((resolve, reject) => {
    const transaction = database.transaction([STORE_NAME], 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.put(data, key);

    request.onsuccess = () => {
      console.log(`保存 ${key} 到 IndexedDB 成功`);
      resolve();
    };

    request.onerror = () => {
      console.error(`保存 ${key} 到 IndexedDB 失败:`, request.error);
      reject(request.error);
    };
  });
}

async function initAvatarLibrary() {
  if (isInitialized) return;

  try {
    avatarLibrary = await loadAvatarData<AvatarLibrary>(
      AVATAR_LIBRARY_KEY,
      defaultAvatarLibrary,
      '头像库'
    );

    avatarState = await loadAvatarData<AvatarState>(
      AVATAR_STATE_KEY,
      defaultAvatarState,
      '头像状态'
    );
  } catch (error) {
    console.error('加载头像库失败:', error);
  }

  isInitialized = true;
}

async function loadAvatarData<T>(
  key: string,
  defaultData: T,
  dataName: string
): Promise<T> {
  const savedData = await loadFromIndexedDB<T>(key);
  if (savedData && typeof savedData === 'object') {
    console.log(`从 IndexedDB 加载${dataName}成功`);
    return { ...defaultData, ...savedData };
  }
  console.log(`IndexedDB 中未找到${dataName}数据，使用默认数据`);
  return { ...defaultData };
}

export async function loadAvatarLibrary(): Promise<AvatarLibrary> {
  if (isInitialized) {
    return avatarLibrary;
  }

  try {
    await openDatabase();

    const savedLibrary = await loadFromIndexedDB<AvatarLibrary>(AVATAR_LIBRARY_KEY);
    if (savedLibrary && typeof savedLibrary === 'object') {
      avatarLibrary = {
        ...defaultAvatarLibrary,
        ...savedLibrary,
      };
      console.log('从 IndexedDB 加载头像库成功');
    } else {
      console.log('IndexedDB 中未找到头像库数据，使用默认头像库');
    }

    const savedState = await loadFromIndexedDB<AvatarState>(AVATAR_STATE_KEY);
    if (savedState && typeof savedState === 'object') {
      avatarState = {
        ...defaultAvatarState,
        ...savedState,
      };
      console.log('从 IndexedDB 加载头像状态成功');
    } else {
      console.log('IndexedDB 中未找到头像状态数据，使用默认状态');
    }

    isInitialized = true;
  } catch (error) {
    console.error('加载头像库失败:', error);
  }

  return avatarLibrary;
}

export function getAvatarLibrary(): AvatarLibrary {
  return avatarLibrary;
}

export function getCharacterAvatarLibrary(characterName: string): Record<number, string> {
  if (avatarLibrary[characterName]) {
    return avatarLibrary[characterName];
  }

  const defaultAvatars = avatarLibrary.default;
  const nonZeroAvatarIds = Object.keys(defaultAvatars)
    .map(Number)
    .filter(id => id > 0);

  if (nonZeroAvatarIds.length > 0) {
    const firstAvatarId = Math.min(...nonZeroAvatarIds);
    return {
      0: defaultAvatars[firstAvatarId] || '',
      [firstAvatarId]: defaultAvatars[firstAvatarId] || '',
    };
  }

  return avatarLibrary.default;
}

export function getCurrentAvatarId(characterName: string): number {
  const current = avatarState[characterName]?.current;
  return current && current > 0 ? current : DEFAULT_AVATAR_ID;
}

export function getAvatarHistoryIds(characterName: string): number[] {
  return avatarState[characterName]?.history || [];
}

export function getAvatarUrl(characterName: string, avatarId?: number): string {
  const actualAvatarId = avatarId !== undefined ? avatarId : getCurrentAvatarId(characterName);
  const charAvatarLibrary = getCharacterAvatarLibrary(characterName);
  const avatarUrl = charAvatarLibrary[actualAvatarId];

  console.log(`获取头像: ${characterName}, ID: ${actualAvatarId}, URL: ${avatarUrl?.substring(0, 50)}...`);

  if (avatarUrl) {
    return avatarUrl;
  }

  // 如果找不到头像，尝试返回 ID 为 1 的头像（默认头像）
  if (charAvatarLibrary[1]) {
    console.log(`使用默认头像 (ID: 1) for ${characterName}`);
    return charAvatarLibrary[1];
  }

  if (actualAvatarId === 0 && !avatarLibrary[characterName]) {
    const defaultAvatars = avatarLibrary.default;
    const nonZeroAvatarIds = Object.keys(defaultAvatars)
      .map(Number)
      .filter(id => id > 0);

    if (nonZeroAvatarIds.length > 0) {
      const firstAvatarId = Math.min(...nonZeroAvatarIds);
      return defaultAvatars[firstAvatarId] || '';
    }
  }

  console.log(`未找到头像 for ${characterName}`);
  return '';
}

export async function setCurrentAvatarId(characterName: string, avatarId: number): Promise<void> {
  if (!avatarState[characterName]) {
    avatarState[characterName] = { current: 0, history: [] };
  }

  const currentAvatarValue = avatarState[characterName].current || 0;
  const history = avatarState[characterName].history || [];

  let newHistory = [...history];
  if (currentAvatarValue !== 0 && currentAvatarValue !== avatarId && !newHistory.includes(currentAvatarValue)) {
    newHistory = [currentAvatarValue, ...newHistory].slice(0, MAX_HISTORY_SIZE);
  }

  if (avatarId !== 0 && !newHistory.includes(avatarId)) {
    newHistory = [avatarId, ...newHistory].slice(0, MAX_HISTORY_SIZE);
  }

  avatarState[characterName].current = avatarId;
  avatarState[characterName].history = newHistory;

  await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
}

export async function addAvatar(characterName: string, avatarId: number, url: string): Promise<void> {
  if (!avatarLibrary[characterName]) {
    avatarLibrary[characterName] = {};
  }
  avatarLibrary[characterName][avatarId] = url;
  await saveToIndexedDB(AVATAR_LIBRARY_KEY, avatarLibrary);
}

export async function deleteAvatar(characterName: string, avatarId: number): Promise<void> {
  if (avatarLibrary[characterName] && avatarLibrary[characterName][avatarId] !== undefined) {
    delete avatarLibrary[characterName][avatarId];
    await saveToIndexedDB(AVATAR_LIBRARY_KEY, avatarLibrary);
  }

  if (avatarState[characterName]) {
    const history = avatarState[characterName].history || [];
    const newHistory = history.filter(id => id !== avatarId);
    avatarState[characterName].history = newHistory;

    if (avatarState[characterName].current === avatarId) {
      avatarState[characterName].current = 0;
    }

    await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
  }
}

export async function removeFromHistory(characterName: string, avatarId: number): Promise<void> {
  if (avatarState[characterName]) {
    const history = avatarState[characterName].history || [];
    const newHistory = history.filter(id => id !== avatarId);
    avatarState[characterName].history = newHistory;
    await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
  }
}

export function getNextAvatarId(characterName: string): number {
  const charAvatarLibrary = getCharacterAvatarLibrary(characterName);
  const existingIds = Object.keys(charAvatarLibrary)
    .map(Number)
    .filter(id => id > 0);
  if (existingIds.length === 0) {
    return 1;
  }
  return Math.max(...existingIds) + 1;
}

export async function clearAvatarLibrary(): Promise<void> {
  avatarLibrary = { ...defaultAvatarLibrary };
  avatarState = { ...defaultAvatarState };
  await saveToIndexedDB(AVATAR_LIBRARY_KEY, avatarLibrary);
  await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
}

export function exportAvatarLibrary(): string {
  return JSON.stringify({ library: avatarLibrary, state: avatarState }, null, 2);
}

export async function importAvatarLibrary(jsonString: string): Promise<boolean> {
  try {
    const imported = JSON.parse(jsonString);
    if (typeof imported === 'object' && imported !== null) {
      if (imported.library) {
        avatarLibrary = { ...defaultAvatarLibrary, ...imported.library };
        await saveToIndexedDB(AVATAR_LIBRARY_KEY, avatarLibrary);
      }
      if (imported.state) {
        avatarState = { ...defaultAvatarState, ...imported.state };
        await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
      }
      return true;
    }
    return false;
  } catch (error) {
    console.error('导入头像库失败:', error);
    return false;
  }
}

