export async function initializeDefaultAvatars(): Promise<void> {
  await loadAvatarLibrary();

  let hasChanges = false;

  for (const [characterName, avatarUrl] of Object.entries(initialAvatarData)) {
    if (!avatarLibrary[characterName]) {
      avatarLibrary[characterName] = {};
    }

    if (!avatarLibrary[characterName][1]) {
      avatarLibrary[characterName][1] = avatarUrl;
      hasChanges = true;
      console.log(`为 ${characterName} 设置初始头像`);
    }

    if (!avatarState[characterName]) {
      avatarState[characterName] = { current: 1, history: [] };
      hasChanges = true;
      console.log(`为 ${characterName} 设置初始头像状态`);
    } else if (avatarState[characterName].current === 0) {
      avatarState[characterName].current = 1;
      hasChanges = true;
      console.log(`更新 ${characterName} 的头像状态为 1`);
    }
  }

  if (hasChanges) {
    await saveToIndexedDB(AVATAR_LIBRARY_KEY, avatarLibrary);
    await saveToIndexedDB(AVATAR_STATE_KEY, avatarState);
    console.log('初始头像数据初始化完成并保存');
  } else {
    console.log('初始头像数据已存在，无需更新');
  }
}
