import { waitUntil } from 'async-wait-until';
import App from './App.vue';
import './global.css';
import { initializeDefaultAvatars } from './avatarLibrary';
import { loadCharacterIntros, reloadCharacterIntros, syncCharacterIntrosToWorldbook } from './characterIntro';
/**
 * 同步变量结构中的角色列表到角色介绍世界书
 * 自动为新角色在世界书中创建空条目
 */
async function syncCharactersToWorldbook() {
    try {
        // 从变量结构中获取角色列表
        const variables = getVariables({ type: 'message' });
        const characterList = variables?.stat_data?.角色列表;
        if (!characterList || typeof characterList !== 'object') {
            console.log('变量结构中暂无角色列表，跳过同步');
            return;
        }
        const characterNames = Object.keys(characterList);
        console.log('从变量结构读取到角色列表:', characterNames);
        if (characterNames.length === 0) {
            console.log('角色列表为空，跳过同步');
            return;
        }
        // 同步到世界书
        await syncCharacterIntrosToWorldbook(characterNames);
    }
    catch (error) {
        console.error('同步角色列表到世界书失败:', error);
    }
}
$(async () => {
    await waitGlobalInitialized('Mvu');
    await waitUntil(() => _.has(getVariables({ type: 'message' }), 'stat_data'));
    await initializeDefaultAvatars();
    // 先加载角色介绍
    await loadCharacterIntros();
    // 同步角色列表到世界书（自动为新角色创建空条目）
    await syncCharactersToWorldbook();
    // 同步完成后重新加载角色介绍（确保新添加的角色也被加载）
    await reloadCharacterIntros();
    createApp(App).use(createPinia()).mount('#app');
});
