interface CharacterIntro {
  name: string;
  content: string;
}

// 类型定义
type PartialDeep<T> = {
  [P in keyof T]?: T[P] extends object ? PartialDeep<T[P]> : T[P];
};

const characterIntros: Map<string, string> = new Map();
let isLoaded = false;

/**
 * 解析 YAML 格式的角色介绍内容
 * 支持格式:
 * - name: 角色名
 *   content: |
 *     角色介绍内容...
 */
function parseCharacterIntroYaml(yamlContent: string): CharacterIntro[] {
  const characters: CharacterIntro[] = [];

  // 按行分割
  const lines = yamlContent.split('\n');
  let currentChar: CharacterIntro | null = null;
  let isInContent = false;
  let contentIndent = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmedLine = line.trim();

    // 跳过空行和注释
    if (!trimmedLine || trimmedLine.startsWith('#')) {
      continue;
    }

    // 检测新的角色条目开始 (以 "- name:" 开头)
    const nameMatch = line.match(/^-\s*name:\s*(.+)$/);
    if (nameMatch) {
      // 保存之前的角色
      if (currentChar) {
        characters.push(currentChar);
      }
      // 开始新角色
      currentChar = {
        name: nameMatch[1].trim(),
        content: '',
      };
      isInContent = false;
      continue;
    }

    // 检测 content: 字段开始
    if (currentChar && !isInContent) {
      const contentMatch = line.match(/^(\s*)content:\s*([|>])?(.*)$/);
      if (contentMatch) {
        isInContent = true;
        contentIndent = contentMatch[1].length + 2; // content: 的缩进 + 2
        const inlineContent = contentMatch[3]?.trim();
        if (inlineContent) {
          currentChar.content = inlineContent;
        }
        continue;
      }
    }

    // 读取 content 的多行内容
    if (currentChar && isInContent) {
      const lineIndent = line.match(/^(\s*)/)?.[1].length || 0;

      // 检测新的角色条目开始（缩进减少）
      if (trimmedLine.startsWith('- name:') && lineIndent <= contentIndent) {
        characters.push(currentChar);
        const nameMatch = line.match(/^-\s*name:\s*(.+)$/);
        if (nameMatch) {
          currentChar = {
            name: nameMatch[1].trim(),
            content: '',
          };
          isInContent = false;
        }
        continue;
      }

      // 如果缩进足够，认为是 content 的内容
      if (lineIndent >= contentIndent) {
        const contentLine = line.slice(contentIndent);
        if (currentChar.content) {
          currentChar.content += '\n' + contentLine;
        } else {
          currentChar.content = contentLine;
        }
      } else if (trimmedLine) {
        // 缩进减少，可能 content 结束了
        isInContent = false;
      }
    }
  }

  // 保存最后一个角色
  if (currentChar) {
    characters.push(currentChar);
  }

  return characters;
}

export async function loadCharacterIntros(): Promise<void> {
  if (isLoaded) return;
  await reloadCharacterIntros();
  isLoaded = true;
}

async function findWorldbookWithIntro(): Promise<{ worldbookName: string; entry: WorldbookEntry } | null> {
  const charWorldbooks = await getCharWorldbookNames('current');
  const worldbookNames = [charWorldbooks.primary, ...charWorldbooks.additional].filter(
    (name): name is string => name !== null,
  );

  for (const worldbookName of worldbookNames) {
    try {
      const worldbook = await getWorldbook(worldbookName);
      const introEntry = worldbook.find(entry => entry.name === '角色介绍');
      if (introEntry) {
        return { worldbookName, entry: introEntry };
      }
    } catch (error) {
      console.log(`读取世界书 "${worldbookName}" 失败:`, error);
    }
  }
  return null;
}

export async function reloadCharacterIntros(): Promise<void> {
  try {
    console.log('当前角色卡绑定的世界书:', await getCharWorldbookNames('current'));

    const result = await findWorldbookWithIntro();
    if (!result) {
      console.log('未在任何绑定的世界书中找到名为"角色介绍"的条目');
      return;
    }

    const { worldbookName, entry: introEntry } = result;
    console.log(`在世界书 "${worldbookName}" 中找到角色介绍条目`);
    console.log('角色介绍条目内容预览:', introEntry.content?.substring(0, 200));

    if (!introEntry.content) {
      console.log('角色介绍条目内容为空');
      return;
    }

    const characters = parseCharacterIntroYaml(introEntry.content);
    console.log('解析到的角色数量:', characters.length);

    for (const char of characters) {
      if (char.name) {
        characterIntros.set(char.name, (char.content || '').trim());
        console.log(`加载角色介绍: ${char.name}, 内容长度: ${char.content?.length || 0}`);
      }
    }

    console.log('从世界书条目加载角色介绍成功，共', characterIntros.size, '个角色');
  } catch (error) {
    console.log('加载角色介绍失败:', error);
  }
}

export function getCharacterIntro(characterName: string): string {
  return characterIntros.get(characterName) || '';
}

export function hasCharacterIntro(characterName: string): boolean {
  return characterIntros.has(characterName) && characterIntros.get(characterName) !== '';
}

function generateYamlContent(characters: CharacterIntro[]): string {
  return characters
    .map(char => {
      const contentLines = char.content
        ? char.content
            .split('\n')
            .map(line => '    ' + line)
            .join('\n')
        : '';
      return `- name: ${char.name}\n  content: |\n${contentLines || '    '}`;
    })
    .join('\n\n');
}

async function getTargetWorldbook(): Promise<{ name: string; entry: WorldbookEntry | null } | null> {
  const charWorldbooks = await getCharWorldbookNames('current');
  const worldbookNames = [charWorldbooks.primary, ...charWorldbooks.additional].filter(
    (name): name is string => name !== null,
  );

  for (const wbName of worldbookNames) {
    try {
      const worldbook = await getWorldbook(wbName);
      const entry = worldbook.find(e => e.name === '角色介绍');
      if (entry) {
        return { name: wbName, entry };
      }
    } catch (error) {
      console.log(`读取世界书 "${wbName}" 失败:`, error);
    }
  }

  if (worldbookNames.length > 0) {
    return { name: worldbookNames[0], entry: null };
  }
  return null;
}

/**
 * 同步角色列表到角色介绍世界书
 * 为变量结构中存在的每个角色在世界书中创建对应的条目（如果不存在）
 * @param characterNames 角色名称列表
 */
export async function syncCharacterIntrosToWorldbook(characterNames: string[]): Promise<void> {
  try {
    console.log('开始同步角色介绍世界书，角色列表:', characterNames);

    const target = await getTargetWorldbook();
    if (!target) {
      console.log('没有找到可用的世界书来同步角色介绍');
      return;
    }

    const { name: targetWorldbookName, entry: introEntry } = target;
    console.log('目标世界书:', targetWorldbookName);

    // 解析现有的角色介绍
    let existingCharacters: CharacterIntro[] = [];
    if (introEntry?.content) {
      existingCharacters = parseCharacterIntroYaml(introEntry.content);
    }

    const existingNames = new Set(existingCharacters.map(c => c.name));
    console.log('已有的角色:', Array.from(existingNames));

    // 找出需要添加的新角色
    const newCharacters = characterNames.filter(name => !existingNames.has(name));
    console.log('需要添加的新角色:', newCharacters);

    if (newCharacters.length === 0) {
      console.log('所有角色已存在于角色介绍中，无需同步');
      return;
    }

    // 为新角色创建 YAML 条目
    const newYamlEntries = newCharacters.map(name => ({
      name: name,
      content: '',
    }));

    // 合并现有角色和新角色
    const allCharacters = [...existingCharacters, ...newYamlEntries];

    // 更新世界书条目
    await updateWorldbookWith(targetWorldbookName, worldbook => {
      const entry = worldbook.find(e => e.name === '角色介绍');
      const newYamlContent = generateYamlContent(allCharacters);
      if (entry) {
        entry.content = newYamlContent;
      } else {
        // 如果条目不存在，创建新条目
        worldbook.push({
          uid: Date.now(),
          name: '角色介绍',
          content: newYamlContent,
          enabled: true,
          strategy: {
            type: 'constant',
            keys: [],
            keys_secondary: { logic: 'and_any', keys: [] },
            scan_depth: 'same_as_global',
          },
          position: {
            type: 'before_character_definition',
            role: 'system',
            depth: 0,
            order: 0,
          },
          probability: 100,
          recursion: {
            prevent_incoming: false,
            prevent_outgoing: false,
            delay_until: null,
          },
          effect: {
            sticky: null,
            cooldown: null,
            delay: null,
          },
        } as WorldbookEntry);
      }
      return worldbook;
    });

    console.log(`成功添加 ${newCharacters.length} 个新角色到角色介绍:`, newCharacters);

    // 更新本地缓存
    for (const name of newCharacters) {
      characterIntros.set(name, '');
    }
  } catch (error) {
    console.error('同步角色介绍失败:', error);
  }
}

/**
 * 更新角色的介绍内容
 * @param characterName 角色名称
 * @param content 介绍内容
 */
export async function updateCharacterIntro(characterName: string, content: string): Promise<void> {
  try {
    const target = await getTargetWorldbook();
    if (!target?.entry) {
      console.log('没有找到包含角色介绍的世界书');
      return;
    }

    await updateWorldbookWith(target.name, worldbook => {
      const entry = worldbook.find(e => e.name === '角色介绍');
      if (entry?.content) {
        const characters = parseCharacterIntroYaml(entry.content);
        const charIndex = characters.findIndex(c => c.name === characterName);

        if (charIndex >= 0) {
          characters[charIndex].content = content;
        } else {
          characters.push({ name: characterName, content });
        }

        entry.content = generateYamlContent(characters);
      }
      return worldbook;
    });

    characterIntros.set(characterName, content);
    console.log(`更新角色 ${characterName} 的介绍成功`);
  } catch (error) {
    console.error(`更新角色 ${characterName} 的介绍失败:`, error);
  }
}
